SELECT 
FROM BPM_PROCESS_LISTENER


        AND LISTENER_NAME LIKE '%' || #{listenerName, jdbcType=VARCHAR} || '%'


        AND LISTENER_TYPE_CODE = #{listenerTypeCode, jdbcType=VARCHAR}


        AND LISTENER_STATUS = #{listenerStatus, jdbcType=DECIMAL}



ORDER BY CREATE_TIME DESC

SELECT 
FROM BPM_PROCESS_LISTENER
WHERE ID = #{id, jdbcType=BIGINT}
